import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import {insureBlogStrings } from './config';
import { insureBlogActions } from './actions';
import { ArticleItem, Subheader, SimplePagination } from '../../includes';
import { insureUtilStrings } from '../utils';
import { insureRouteNames } from '../routeNames';
import { KnowledgeArea } from '../Home/KnowledeArea';

const style = theme => ({
    root: {
    },
    container : {
        margin :20,
        marginBottom : 50,
    },
    pageRoot : {
        marginTop : 50,
    }
})
class _Blogs extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : 20,
        }
    }
    
    componentDidMount() {
        const {
            dispatch,
            [insureBlogStrings.blogs] : blogs,
        } = this.props;
        const {lastId, rows} = this.state;
        if(!blogs) insureBlogActions.getBlogs(lastId, rows)(dispatch);
    }
    
    render() {
        const {
            classes,
            [insureBlogStrings.blogs] : blogs,
            [insureUtilStrings.subheadImage] : subheadImage,
            [insureUtilStrings.backendBaseUrl] : baseUrl
        } = this.props;
        return (
            <div className={classes.root}>
                <Subheader
                    title="Blogs"
                    image_url={subheadImage}/>
                <div className={classes.container}>
                    {blogs && blogs.map((item, index)=>
                        <ArticleItem 
                            baseUrl={baseUrl}
                            toUrl={{
                                pathname : insureRouteNames.blogView_+item.name, state : item
                            }} 
                            key={index} {...item}/>
                    )}
                    <SimplePagination classes={{
                        root : classes.pageRoot
                    }}/>
                </div>
                <KnowledgeArea/>
            </div>
        );
    }
}


_Blogs.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureBlogReducer, insureUtilReducer}) => ({
    [insureBlogStrings.blogs] : insureBlogReducer[insureBlogStrings.blogs],
    [insureUtilStrings.subheadImage] : insureUtilReducer[insureUtilStrings.subheadImage],
    [insureUtilStrings.backendBaseUrl] : insureUtilReducer[insureUtilStrings.backendBaseUrl],
})


export const Blogs = connect(mapStateToProps)(withStyles(style)(_Blogs));
export {Blogs as default}